import React, { useState, useEffect } from "react";
import Nav from "../Nav/Nav";
import "./CinemaManagement.css";

// Slot Price Editor Component
function SlotPriceEditor({ slotType, slotNumber, currentPrice, cinemaId, onPriceUpdate }) {
  const [price, setPrice] = useState(currentPrice);
  const [isEditing, setIsEditing] = useState(false);
  const [isUpdating, setIsUpdating] = useState(false);

  const handleSave = async () => {
    if (price < 0) {
      alert("Price cannot be negative");
      return;
    }

    setIsUpdating(true);
    const success = await onPriceUpdate(cinemaId, slotType, slotNumber, price);
    setIsUpdating(false);

    if (success) {
      setIsEditing(false);
    }
  };

  const handleCancel = () => {
    setPrice(currentPrice);
    setIsEditing(false);
  };

  return (
    <div className="slot-price-editor">
      <div className="slot-info">
        <span className="slot-name">Slot {slotNumber}</span>
        {isEditing ? (
          <div className="price-input-group">
            <input
              type="number"
              value={price}
              onChange={(e) => setPrice(parseInt(e.target.value) || 0)}
              min="0"
              className="price-input"
              disabled={isUpdating}
            />
            <button 
              className="save-btn"
              onClick={handleSave}
              disabled={isUpdating}
            >
              {isUpdating ? "Saving..." : "Save"}
            </button>
            <button 
              className="cancel-btn"
              onClick={handleCancel}
              disabled={isUpdating}
            >
              Cancel
            </button>
          </div>
        ) : (
          <div className="price-display">
            <span className="price">₹{currentPrice}</span>
            <button 
              className="edit-btn"
              onClick={() => setIsEditing(true)}
            >
              Edit
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

// Step Components
function StepIndicator({ currentStep, totalSteps }) {
  return (
    <div className="step-indicator">
      {Array.from({ length: totalSteps }, (_, i) => (
        <div 
          key={i + 1} 
          className={`step ${i + 1 <= currentStep ? 'active' : ''}`}
        >
          {i + 1}
        </div>
      ))}
    </div>
  );
}

function GeneralDetailsStep({ formData, setFormData }) {
  return (
    <div className="step-content">
      <h3>General Cinema Details</h3>

      <div className="form-group">
        <label>Cinema Name *</label>
        <input
          type="text"
          name="cinema_name"
          value={formData.cinema_name}
          onChange={(e) => setFormData(prev => ({
            ...prev,
            [e.target.name]: e.target.value
          }))}
          required
        />
      </div>

      <div className="form-group">
        <label>Location *</label>
        <input
          type="text"
          name="cinema_location"
          value={formData.cinema_location}
          onChange={(e) => setFormData(prev => ({
            ...prev,
            [e.target.name]: e.target.value
          }))}
          required
        />
      </div>

      <div className="form-group">
        <label>Google Maps Location</label>
        <input
          type="url"
          name="google_maps_location"
          value={formData.google_maps_location}
          onChange={(e) => setFormData(prev => ({
            ...prev,
            [e.target.name]: e.target.value
          }))}
          placeholder="https://maps.google.com/..."
        />
      </div>

      <div className="form-row">
        <div className="form-group">
          <label>Phone</label>
          <input
            type="tel"
            name="phone"
            value={formData.contact_info.phone}
            onChange={(e) => setFormData(prev => ({
              ...prev,
              contact_info: {
                ...prev.contact_info,
                [e.target.name]: e.target.value
              }
            }))}
          />
        </div>
        <div className="form-group">
          <label>Email</label>
          <input
            type="email"
            name="email"
            value={formData.contact_info.email}
            onChange={(e) => setFormData(prev => ({
              ...prev,
              contact_info: {
                ...prev.contact_info,
                [e.target.name]: e.target.value
              }
            }))}
          />
        </div>
      </div>
    </div>
  );
}

function OngoingMovieStep({ movieKey, movieData, setFormData, stepNumber }) {
  const handleMovieChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      ongoing_movies: {
        ...prev.ongoing_movies,
        [movieKey]: {
          ...prev.ongoing_movies[movieKey],
          [field]: value
        }
      }
    }));
  };

  return (
    <div className="step-content">
      <h3>Ongoing Movie {stepNumber} Details</h3>

      <div className="form-group">
        <label>Movie Name *</label>
        <input
          type="text"
          value={movieData.name}
          onChange={(e) => handleMovieChange('name', e.target.value)}
          required
        />
      </div>

      <div className="form-row">
        <div className="form-group">
          <label>Start Date *</label>
          <input
            type="date"
            value={movieData.start_date}
            onChange={(e) => handleMovieChange('start_date', e.target.value)}
            required
          />
        </div>
        <div className="form-group">
          <label>End Date *</label>
          <input
            type="date"
            value={movieData.end_date}
            onChange={(e) => handleMovieChange('end_date', e.target.value)}
            required
          />
        </div>
      </div>

      <div className="form-group">
        <label>Trailer Link (YouTube)</label>
        <input
          type="url"
          value={movieData.trailer_link}
          onChange={(e) => handleMovieChange('trailer_link', e.target.value)}
          placeholder="https://www.youtube.com/watch?v=..."
        />
      </div>

      <div className="slot-pricing-section">
        <h4>Advertisement Slot Pricing</h4>
        <p className="help-text">Set prices for each advertisement slot (default: ₹10,000)</p>

        <div className="pricing-grid">
          <div className="pricing-category">
            <h5>Start Slots (Before Movie)</h5>
            <div className="slot-prices">
              {[1, 2, 3, 4, 5].map(slotNum => (
                <div key={slotNum} className="slot-price-item">
                  <span>Slot {slotNum}:</span>
                  <input
                    type="number"
                    min="0"
                    defaultValue="10000"
                    className="price-input"
                  />
                </div>
              ))}
            </div>
          </div>

          <div className="pricing-category">
            <h5>Interval Slots (During Movie)</h5>
            <div className="slot-prices">
              {[1, 2, 3, 4, 5].map(slotNum => (
                <div key={slotNum} className="slot-price-item">
                  <span>Slot {slotNum}:</span>
                  <input
                    type="number"
                    min="0"
                    defaultValue="10000"
                    className="price-input"
                  />
                </div>
              ))}
            </div>
          </div>

          <div className="pricing-category">
            <h5>End Slots (After Movie)</h5>
            <div className="slot-prices">
              {[1, 2, 3, 4, 5].map(slotNum => (
                <div key={slotNum} className="slot-price-item">
                  <span>Slot {slotNum}:</span>
                  <input
                    type="number"
                    min="0"
                    defaultValue="10000"
                    className="price-input"
                  />
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

function UpcomingMovieStep({ movieKey, movieData, setFormData, stepNumber }) {
  const handleMovieChange = (field, value) => {
    setFormData(prev => ({
      ...prev,
      upcoming_movies: {
        ...prev.upcoming_movies,
        [movieKey]: {
          ...prev.upcoming_movies[movieKey],
          [field]: value
        }
      }
    }));
  };

  return (
    <div className="step-content">
      <h3>Upcoming Movie {stepNumber} Details</h3>

      <div className="form-group">
        <label>Movie Name *</label>
        <input
          type="text"
          value={movieData.name}
          onChange={(e) => handleMovieChange('name', e.target.value)}
          required
        />
      </div>

      <div className="form-group">
        <label>Trailer Link (YouTube)</label>
        <input
          type="url"
          value={movieData.trailer_link}
          onChange={(e) => handleMovieChange('trailer_link', e.target.value)}
          placeholder="https://www.youtube.com/watch?v=..."
        />
      </div>
    </div>
  );
}

function CinemaManagement() {
  const [cinemas, setCinemas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingCinema, setEditingCinema] = useState(null);
  const [showPricingModal, setShowPricingModal] = useState(false);
  const [selectedCinemaForPricing, setSelectedCinemaForPricing] = useState(null);
  const [formData, setFormData] = useState({
    cinema_name: "",
    cinema_location: "",
    google_maps_location: "",
    contact_info: {
      phone: "",
      email: ""
    },
    ongoing_movies: {
      movie_1: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      },
      movie_2: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      },
      movie_3: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      },
      movie_4: {
        name: "",
        start_date: "",
        end_date: "",
        trailer_link: ""
      }
    },
    upcoming_movies: {
      movie_1: {
        name: "",
        trailer_link: ""
      },
      movie_2: {
        name: "",
        trailer_link: ""
      }
    },
    is_active: true
  });

  const [currentStep, setCurrentStep] = useState(1);
  const totalSteps = 7; // General details + 4 ongoing movies + 2 upcoming movies

  // API base URL
  const API_BASE_URL = "http://localhost:5000/api/cinemas";

  // Fetch cinemas from API
  const fetchCinemas = async () => {
    try {
      setLoading(true);
      const response = await fetch(API_BASE_URL);
      const data = await response.json();

      if (data.success) {
        setCinemas(data.data);
      } else {
        console.error("Error fetching cinemas:", data.message);
        alert("Error fetching cinemas: " + data.message);
      }
    } catch (error) {
      console.error("Error fetching cinemas:", error);
      alert("Error fetching cinemas. Please check if the backend server is running.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchCinemas();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;

    if (name.includes(".")) {
      const [parent, child] = name.split(".");
      setFormData(prev => ({
        ...prev,
        [parent]: {
          ...prev[parent],
          [child]: value
        }
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    // Client-side validation
    if (!formData.cinema_name || !formData.cinema_location || !formData.upcoming_movie) {
      alert("Please fill in all required fields (Cinema Name, Location, and Upcoming Movie)");
      return;
    }

    if (!formData.ongoing_movies.movie_1 || !formData.ongoing_movies.movie_2 || 
        !formData.ongoing_movies.movie_3 || !formData.ongoing_movies.movie_4) {
      alert("Please fill in all 4 ongoing movies");
      return;
    }

    try {
      const url = editingCinema ? `${API_BASE_URL}/${editingCinema._id}` : API_BASE_URL;
      const method = editingCinema ? 'PUT' : 'POST';

      console.log("📤 Sending cinema data:", JSON.stringify(formData, null, 2));

      const response = await fetch(url, {
        method: method,
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(formData)
      });

      const data = await response.json();
      console.log("📥 Response from server:", data);

      if (data.success) {
        alert(editingCinema ? "Cinema updated successfully!" : "Cinema added successfully!");
        setShowAddForm(false);
        setEditingCinema(null);
        resetForm();
        // Refresh the cinemas list
        fetchCinemas();
      } else {
        alert("Error: " + data.message);
        if (data.received) {
          console.log("Received fields:", data.received);
        }
      }
    } catch (error) {
      console.error("Error saving cinema:", error);
      alert("Error saving cinema. Please try again.");
    }
  };

  const resetForm = () => {
    setFormData({
      cinema_name: "",
      cinema_location: "",
      google_maps_location: "",
      contact_info: {
        phone: "",
        email: ""
      },
      ongoing_movies: {
        movie_1: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        },
        movie_2: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        },
        movie_3: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        },
        movie_4: {
          name: "",
          start_date: "",
          end_date: "",
          trailer_link: ""
        }
      },
      upcoming_movies: {
        movie_1: {
          name: "",
          trailer_link: ""
        },
        movie_2: {
          name: "",
          trailer_link: ""
        }
      },
      is_active: true
    });
    setCurrentStep(1);
  };

  const handleNext = () => {
    if (currentStep < totalSteps) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handlePrev = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleEdit = (cinema) => {
    setFormData(cinema);
    setEditingCinema(cinema);
    setShowAddForm(true);
    setCurrentStep(1);
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this cinema?")) {
      try {
        const response = await fetch(`${API_BASE_URL}/${id}`, {
          method: 'DELETE'
        });

        const data = await response.json();

        if (data.success) {
          alert("Cinema deleted successfully!");
          // Refresh the cinemas list
          fetchCinemas();
        } else {
          alert("Error: " + data.message);
        }
      } catch (error) {
        console.error("Error deleting cinema:", error);
        alert("Error deleting cinema. Please try again.");
      }
    }
  };

  const toggleStatus = async (id) => {
    try {
      // First get the current cinema data
      const cinema = cinemas.find(c => c._id === id);
      if (!cinema) return;

      const response = await fetch(`${API_BASE_URL}/${id}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...cinema,
          is_active: !cinema.is_active
        })
      });

      const data = await response.json();

      if (data.success) {
        alert(`Cinema ${!cinema.is_active ? 'activated' : 'deactivated'} successfully!`);
        // Refresh the cinemas list
        fetchCinemas();
      } else {
        alert("Error: " + data.message);
      }
    } catch (error) {
      console.error("Error toggling cinema status:", error);
      alert("Error updating cinema status. Please try again.");
    }
  };

  const handlePricingClick = (cinema) => {
    setSelectedCinemaForPricing(cinema);
    setShowPricingModal(true);
  };

  const updateSlotPrice = async (cinemaId, slotType, slotNumber, newPrice) => {
    try {
      const response = await fetch(`${API_BASE_URL}/${cinemaId}/slot-prices`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          slotType,
          slotNumber,
          price: newPrice
        })
      });

      const data = await response.json();

      if (data.success) {
        // Refresh the cinemas list to show updated prices
        fetchCinemas();
        return true;
      } else {
        alert("Error updating price: " + data.message);
        return false;
      }
    } catch (error) {
      console.error("Error updating slot price:", error);
      alert("Error updating slot price. Please try again.");
      return false;
    }
  };

  return (
    <div>
      {/* Navbar */}
      <Nav />

      {/* Hero Section */}
      <section className="hero">
        <div className="hero-content">
          <h1>Cinema Management</h1>
          <p>Manage your cinema halls and movie listings</p>
          <button 
            className="cta-btn"
            onClick={() => setShowAddForm(true)}
          >
            Add New Cinema
          </button>
        </div>
      </section>

      {/* Add/Edit Form */}
      {showAddForm && (
        <section className="form-section">
          <div className="container">
            <div className="form-container">
              <div className="form-header">
                <h2>{editingCinema ? "Edit Cinema" : "Add New Cinema"}</h2>
                <button 
                  className="close-btn"
                  onClick={() => {
                    setShowAddForm(false);
                    setEditingCinema(null);
                    resetForm();
                  }}
                >

                </button>
              </div>

              <form onSubmit={handleSubmit} className="cinema-form">
                <div className="form-row">
                  <div className="form-group">
                    <label>Cinema Name *</label>
                    <input
                      type="text"
                      name="cinema_name"
                      value={formData.cinema_name}
                      onChange={handleInputChange}
                      required
                    />
                  </div>
                  <div className="form-group">
                    <label>Location *</label>
                    <input
                      type="text"
                      name="cinema_location"
                      value={formData.cinema_location}
                      onChange={handleInputChange}
                      required
                    />
                  </div>
                </div>

                <div className="form-group">
                  <label>Ongoing Movies *</label>
                  <div className="movies-grid">
                    <input
                      type="text"
                      name="ongoing_movies.movie_1"
                      value={formData.ongoing_movies.movie_1}
                      onChange={handleInputChange}
                      placeholder="Movie 1"
                      required
                    />
                    <input
                      type="text"
                      name="ongoing_movies.movie_2"
                      value={formData.ongoing_movies.movie_2}
                      onChange={handleInputChange}
                      placeholder="Movie 2"
                      required
                    />
                    <input
                      type="text"
                      name="ongoing_movies.movie_3"
                      value={formData.ongoing_movies.movie_3}
                      onChange={handleInputChange}
                      placeholder="Movie 3"
                      required
                    />
                    <input
                      type="text"
                      name="ongoing_movies.movie_4"
                      value={formData.ongoing_movies.movie_4}
                      onChange={handleInputChange}
                      placeholder="Movie 4"
                      required
                    />
                  </div>
                </div>

                <div className="form-group">
                  <label>Upcoming Movie *</label>
                  <input
                    type="text"
                    name="upcoming_movie"
                    value={formData.upcoming_movie}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="form-group">
                  <label>Movie Trailer (YouTube URL)</label>
                  <input
                    type="url"
                    name="upcoming_movie_trailer"
                    value={formData.upcoming_movie_trailer}
                    onChange={handleInputChange}
                    placeholder="https://www.youtube.com/watch?v=..."
                  />
                </div>

                <div className="form-group">
                  <label>Google Maps Location</label>
                  <input
                    type="url"
                    name="google_maps_location"
                    value={formData.google_maps_location}
                    onChange={handleInputChange}
                    placeholder="https://maps.google.com/..."
                  />
                </div>

                <div className="form-row">
                  <div className="form-group">
                    <label>Phone</label>
                    <input
                      type="tel"
                      name="contact_info.phone"
                      value={formData.contact_info.phone}
                      onChange={handleInputChange}
                    />
                  </div>
                  <div className="form-group">
                    <label>Email</label>
                    <input
                      type="email"
                      name="contact_info.email"
                      value={formData.contact_info.email}
                      onChange={handleInputChange}
                    />
                  </div>
                </div>

                <div className="form-group">
                  <label className="checkbox-label">
                    <input
                      type="checkbox"
                      name="is_active"
                      checked={formData.is_active}
                      onChange={(e) => setFormData(prev => ({
                        ...prev,
                        is_active: e.target.checked
                      }))}
                    />
                    Active Cinema
                  </label>
                </div>

                <div className="form-actions">
                  <button type="button" onClick={() => {
                    setShowAddForm(false);
                    setEditingCinema(null);
                    resetForm();
                  }} className="btn-secondary">
                    Cancel
                  </button>
                  <button type="submit" className="btn-primary">
                    {editingCinema ? "Update Cinema" : "Add Cinema"}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </section>
      )}

      {/* Cinemas List */}
      <section className="cinemas-section">
        <div className="container">
          <h2>Your Cinemas</h2>

          {loading ? (
            <div className="loading">Loading cinemas...</div>
          ) : cinemas.length === 0 ? (
            <div className="no-cinemas">
              <h3>No cinemas found</h3>
              <p>Add your first cinema to get started.</p>
            </div>
          ) : (
            <div className="cinemas-grid">
              {cinemas.map((cinema) => (
                <div key={cinema._id} className="cinema-card">
                  <div className="cinema-header">
                    <h3>{cinema.cinema_name}</h3>
                    <span className={`status ${cinema.is_active ? "active" : "inactive"}`}>
                      {cinema.is_active ? "Active" : "Inactive"}
                    </span>
                  </div>

                  <div className="cinema-details">
                    <p className="location"> {cinema.cinema_location}</p>

                    <div className="movies-section">
                      <h4>Ongoing Movies:</h4>
                      <ul className="movies-list">
                        <li>{cinema.ongoing_movies.movie_1}</li>
                        <li>{cinema.ongoing_movies.movie_2}</li>
                        <li>{cinema.ongoing_movies.movie_3}</li>
                        <li>{cinema.ongoing_movies.movie_4}</li>
                      </ul>
                    </div>

                    <div className="upcoming-section">
                      <h4>Upcoming:</h4>
                      <p>{cinema.upcoming_movie}</p>
                      {cinema.upcoming_movie_trailer && (
                        <a href={cinema.upcoming_movie_trailer} target="_blank" rel="noopener noreferrer" className="trailer-link">
                          Watch Trailer
                        </a>
                      )}
                    </div>

                    {cinema.google_maps_location && (
                      <div className="location-section">
                        <h4>Location:</h4>
                        <a href={cinema.google_maps_location} target="_blank" rel="noopener noreferrer" className="map-link">
                          View on Google Maps
                        </a>
                      </div>
                    )}

                    {cinema.advertisement_slots && (
                      <div className="advertisement-slots">
                        <h4>Advertisement Slots:</h4>
                        <div className="slots-summary">
                          <div className="slot-category">
                            <span className="slot-label">Start (5 slots):</span>
                            <span className="slot-price">₹{cinema.advertisement_slots.start_slots?.[0]?.price || 10000} each</span>
                          </div>
                          <div className="slot-category">
                            <span className="slot-label">Interval (5 slots):</span>
                            <span className="slot-price">₹{cinema.advertisement_slots.interval_slots?.[0]?.price || 10000} each</span>
                          </div>
                          <div className="slot-category">
                            <span className="slot-label">End (5 slots):</span>
                            <span className="slot-price">₹{cinema.advertisement_slots.end_slots?.[0]?.price || 10000} each</span>
                          </div>
                        </div>
                      </div>
                    )}

                    {cinema.contact_info.phone && (
                      <p className="contact"> {cinema.contact_info.phone}</p>
                    )}
                    {cinema.contact_info.email && (
                      <p className="contact"> {cinema.contact_info.email}</p>
                    )}
                  </div>

                  <div className="cinema-actions">
                    <button 
                      className="btn-edit"
                      onClick={() => handleEdit(cinema)}
                    >
                      Edit
                    </button>
                    <button 
                      className="btn-pricing"
                      onClick={() => handlePricingClick(cinema)}
                    >
                      Manage Pricing
                    </button>
                    <button 
                      className="btn-toggle"
                      onClick={() => toggleStatus(cinema._id)}
                    >
                      {cinema.is_active ? "Deactivate" : "Activate"}
                    </button>
                    <button 
                      className="btn-delete"
                      onClick={() => handleDelete(cinema._id)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </section>

      {/* Pricing Management Modal */}
      {showPricingModal && selectedCinemaForPricing && (
        <div className="modal-overlay">
          <div className="pricing-modal">
            <div className="modal-header">
              <h2>Manage Advertisement Slot Pricing</h2>
              <h3>{selectedCinemaForPricing.cinema_name}</h3>
              <button 
                className="close-btn"
                onClick={() => {
                  setShowPricingModal(false);
                  setSelectedCinemaForPricing(null);
                }}
              >
                ×
              </button>
            </div>

            <div className="pricing-content">
              {selectedCinemaForPricing.advertisement_slots && (
                <>
                  {/* Start Slots Pricing */}
                  <div className="pricing-section">
                    <h4>Start Slots (Before Movie)</h4>
                    <div className="slots-pricing-grid">
                      {selectedCinemaForPricing.advertisement_slots.start_slots?.map((slot, index) => (
                        <SlotPriceEditor
                          key={`start_${slot.slot_number}`}
                          slotType="start_slots"
                          slotNumber={slot.slot_number}
                          currentPrice={slot.price}
                          cinemaId={selectedCinemaForPricing._id}
                          onPriceUpdate={updateSlotPrice}
                        />
                      ))}
                    </div>
                  </div>

                  {/* Interval Slots Pricing */}
                  <div className="pricing-section">
                    <h4>Interval Slots (During Movie)</h4>
                    <div className="slots-pricing-grid">
                      {selectedCinemaForPricing.advertisement_slots.interval_slots?.map((slot, index) => (
                        <SlotPriceEditor
                          key={`interval_${slot.slot_number}`}
                          slotType="interval_slots"
                          slotNumber={slot.slot_number}
                          currentPrice={slot.price}
                          cinemaId={selectedCinemaForPricing._id}
                          onPriceUpdate={updateSlotPrice}
                        />
                      ))}
                    </div>
                  </div>

                  {/* End Slots Pricing */}
                  <div className="pricing-section">
                    <h4>End Slots (After Movie)</h4>
                    <div className="slots-pricing-grid">
                      {selectedCinemaForPricing.advertisement_slots.end_slots?.map((slot, index) => (
                        <SlotPriceEditor
                          key={`end_${slot.slot_number}`}
                          slotType="end_slots"
                          slotNumber={slot.slot_number}
                          currentPrice={slot.price}
                          cinemaId={selectedCinemaForPricing._id}
                          onPriceUpdate={updateSlotPrice}
                        />
                      ))}
                    </div>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="footer">
        <div className="footer-content">
          <div className="footer-section">
            <h3>D&S Creations</h3>
            <p>Your premier destination for cinema advertising and entertainment.</p>
          </div>
          <div className="footer-section">
            <h4>Quick Links</h4>
            <ul>
              <li><a href="/mainhome">Home</a></li>
              <li><a href="/cinema-management">Cinema Management</a></li>
              <li><a href="/new-reservation">New Reservation</a></li>
              <li><a href="/my-reservations">My Reservations</a></li>
            </ul>
          </div>
          <div className="footer-section">
            <h4>Contact Info</h4>
            <p>Email: info@dscreations.com</p>
            <p>Phone: +1 (555) 123-4567</p>
          </div>
        </div>
        <div className="footer-bottom">
          <p>&copy; {new Date().getFullYear()} D&S Creations. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
}

export default CinemaManagement;
